import { loadPersistentAgentScreenData } from "@/lib/persistent-agent/server/session";
import { PersistentAgentScreen } from "@/components/persistent-agent/persistent-agent-screen";

export default async function PersistentAgentPage() {
  const screenData = await loadPersistentAgentScreenData({
    chatId: null,
  });

  return <PersistentAgentScreen {...screenData} />;
}

import { notFound } from "next/navigation";

import { loadPersistentAgentScreenData } from "@/lib/persistent-agent/server/session";
import { PersistentAgentScreen } from "@/components/persistent-agent/persistent-agent-screen";

export default async function PersistentAgentConversationPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const screenData = await loadPersistentAgentScreenData({
    chatId: id,
  });

  if (!screenData.initialSession) {
    notFound();
  }

  return <PersistentAgentScreen {...screenData} />;
}

import { handlePersistentAgentChatRequest } from "@/lib/persistent-agent/server/runtime";
import {
  buildPersistentAgentVisitorCookie,
  getOrCreatePersistentAgentVisitorId,
} from "@/lib/persistent-agent/server/viewer-context";

export async function POST(request: Request) {
  const visitor = getOrCreatePersistentAgentVisitorId(request);
  const response = await handlePersistentAgentChatRequest(request, {
    visitorId: visitor.visitorId,
  });

  if (visitor.shouldSetCookie) {
    response.headers.append(
      "set-cookie",
      buildPersistentAgentVisitorCookie(visitor.visitorId)
    );
  }

  return response;
}

import { handlePersistentAgentStreamResumeRequest } from "@/lib/persistent-agent/server/runtime";
import {
  buildPersistentAgentVisitorCookie,
  getOrCreatePersistentAgentVisitorId,
} from "@/lib/persistent-agent/server/viewer-context";

export async function GET(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;
  const visitor = getOrCreatePersistentAgentVisitorId(request);
  const response = await handlePersistentAgentStreamResumeRequest(id, {
    visitorId: visitor.visitorId,
  });

  if (visitor.shouldSetCookie) {
    response.headers.append(
      "set-cookie",
      buildPersistentAgentVisitorCookie(visitor.visitorId)
    );
  }

  return response;
}

import { handlePersistentAgentSessionRequest } from "@/lib/persistent-agent/server/runtime";
import {
  buildPersistentAgentVisitorCookie,
  getOrCreatePersistentAgentVisitorId,
} from "@/lib/persistent-agent/server/viewer-context";

export async function GET(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;
  const visitor = getOrCreatePersistentAgentVisitorId(request);
  const response = await handlePersistentAgentSessionRequest(id, {
    visitorId: visitor.visitorId,
  });

  if (visitor.shouldSetCookie) {
    response.headers.append(
      "set-cookie",
      buildPersistentAgentVisitorCookie(visitor.visitorId)
    );
  }

  return response;
}

import { Badge } from "@/components/ui/badge";
import {
  Breadcrumb,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from "@/components/ui/breadcrumb";
import { ArrowLeft } from "lucide-react";

import {
  getPersistentAgentRuntimeState,
  type PersistentAgentRuntimeState,
} from "@/lib/persistent-agent/server/runtime";
import type { PersistentAgentScreenData } from "@/lib/persistent-agent/server/session";
import { PersistentAgentWorkspace } from "./persistent-agent-workspace";

interface PersistentAgentScreenProps extends PersistentAgentScreenData {
  runtimeState?: PersistentAgentRuntimeState;
}

export function PersistentAgentScreen({
  draftChatId,
  initialSession,
  recentChats,
  runtimeState = getPersistentAgentRuntimeState(),
}: PersistentAgentScreenProps) {
  return (
    <main className="min-h-svh bg-background text-foreground">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-6 px-4 py-6 md:px-6">
        <header className="grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end">
          <div className="space-y-2">
            <Breadcrumb>
              <BreadcrumbList className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                <BreadcrumbItem>
                  <BreadcrumbLink
                    aria-label="Back to demos"
                    className="-ml-1 inline-flex items-center gap-1.5 text-muted-foreground transition-colors hover:text-foreground"
                    href="/"
                  >
                    <ArrowLeft aria-hidden="true" className="size-3.5 shrink-0" />
                    <span>Demo</span>
                  </BreadcrumbLink>
                </BreadcrumbItem>
                <BreadcrumbSeparator className="text-muted-foreground">
                  /
                </BreadcrumbSeparator>
                <BreadcrumbItem>
                  <BreadcrumbPage className="font-normal text-muted-foreground">
                    Persistent &amp; Resume Agent
                  </BreadcrumbPage>
                </BreadcrumbItem>
              </BreadcrumbList>
            </Breadcrumb>
            <h1 className="max-w-3xl font-medium text-2xl tracking-tight">
              Persistent &amp; Resume Agent
            </h1>
            <p className="max-w-3xl text-muted-foreground text-sm/relaxed">
              This demo focuses on one contract: a chat becomes an addressable
              resource at <code>/demos/persistent-agent/[id]</code>, survives
              refresh, and keeps its visitor-private identity through a
              server-set cookie.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{runtimeState.statusLabel}</Badge>
            <Badge variant="outline">{runtimeState.chatModel}</Badge>
            <Badge variant="outline">{runtimeState.persistenceLabel}</Badge>
            <Badge variant="outline">{runtimeState.resumeLabel}</Badge>
          </div>
        </header>

        <div className="lg:h-svh">
          <PersistentAgentWorkspace
            chatModel={runtimeState.chatModel}
            draftChatId={draftChatId}
            initialSession={initialSession}
            isChatAvailable={runtimeState.isChatAvailable}
            nodeVersion={runtimeState.nodeVersion}
            persistenceLabel={runtimeState.persistenceLabel}
            recentChats={recentChats}
            resumeLabel={runtimeState.resumeLabel}
            setupMessage={runtimeState.setupMessage}
          />
        </div>
      </div>
    </main>
  );
}

"use client";

import { useChat } from "@ai-sdk/react";
import { ArrowClockwiseIcon, LinkIcon, RobotIcon } from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Shimmer } from "@/components/ai-elements/shimmer";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { DefaultChatTransport, type UIMessage } from "ai";
import Link from "next/link";
import {
  type Dispatch,
  type SetStateAction,
  useEffect,
  useRef,
  useState,
} from "react";

import type {
  PersistentAgentChatRecord,
  PersistentAgentChatSession,
} from "@/lib/persistent-agent/server/chat-store";
import { shouldShowResumeThinking } from "./resume-pending-state";

function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function formatDateTime(value: string | null) {
  if (!value) {
    return "Pending";
  }

  const date = new Date(value);

  if (Number.isNaN(date.valueOf())) {
    return value;
  }

  return new Intl.DateTimeFormat("en", {
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    month: "short",
  }).format(date);
}

function toConversationPath(chatId: string) {
  return `/demos/persistent-agent/${chatId}`;
}

const nodeVersionPrefixPattern = /^v/;
const resumeRecoveryAttemptLimit = 6;
const persistentAgentSamplePrompts = [
  "Explain the route and storage contract for this persistent chat demo.",
  "Summarize how a user could adapt this demo from in-memory storage to Postgres and Redis.",
  "Give me a concise QA checklist for verifying refresh-safe chat state.",
] as const;

async function loadPersistentAgentSessionSnapshot(chatId: string) {
  const response = await fetch(
    `/api/demos/persistent-agent/${chatId}/session`,
    {
      credentials: "include",
    }
  );

  if (!response.ok) {
    return null;
  }

  return (await response.json()) as PersistentAgentChatSession;
}

function shouldApplyRecoveredSession(
  session: PersistentAgentChatSession,
  messagesLength: number
) {
  return (
    session.messages.length > messagesLength ||
    session.messages.at(-1)?.role !== "user"
  );
}

interface PersistentAgentWorkspaceProps {
  chatModel: string;
  draftChatId: string;
  initialSession: PersistentAgentChatSession | null;
  isChatAvailable: boolean;
  nodeVersion: string;
  persistenceLabel: string;
  recentChats: PersistentAgentChatRecord[];
  resumeLabel: string;
  setupMessage: string | null;
}

function useResumeRecovery(input: {
  chatId: string;
  initialSession: PersistentAgentChatSession | null;
  latestMessageRole: UIMessage["role"] | undefined;
  messagesLength: number;
  setChatMeta: Dispatch<
    SetStateAction<{
      createdAt: string | null;
      id: string;
      updatedAt: string | null;
    }>
  >;
  setMessages: (messages: UIMessage[]) => void;
  status: string;
}) {
  const {
    chatId,
    initialSession,
    latestMessageRole,
    messagesLength,
    setChatMeta,
    setMessages,
    status,
  } = input;
  const shouldRecoverMissedResumeRef = useRef(
    initialSession?.chat.activeStreamId != null ||
      initialSession?.messages.at(-1)?.role === "user"
  );
  const initialMessageCountRef = useRef(initialSession?.messages.length ?? 0);

  useEffect(() => {
    if (!shouldRecoverMissedResumeRef.current) {
      return;
    }

    if (status !== "ready") {
      return;
    }

    if (
      messagesLength > initialMessageCountRef.current ||
      latestMessageRole !== "user"
    ) {
      shouldRecoverMissedResumeRef.current = false;
      return;
    }

    let isCancelled = false;
    let timeoutId: number | undefined;
    let attempt = 0;

    const runRecoveryAttempt = () => {
      attempt += 1;

      loadPersistentAgentSessionSnapshot(chatId).then((session) => {
        if (isCancelled) {
          return;
        }

        if (session && shouldApplyRecoveredSession(session, messagesLength)) {
          shouldRecoverMissedResumeRef.current = false;
          setMessages(session.messages);
          setChatMeta({
            createdAt: session.chat.createdAt,
            id: session.chat.id,
            updatedAt: session.chat.updatedAt,
          });
          return;
        }

        if (attempt >= resumeRecoveryAttemptLimit) {
          shouldRecoverMissedResumeRef.current = false;
          return;
        }

        timeoutId = window.setTimeout(runRecoveryAttempt, 1500);
      });
    };

    timeoutId = window.setTimeout(runRecoveryAttempt, 2500);

    return () => {
      isCancelled = true;
      if (timeoutId) {
        window.clearTimeout(timeoutId);
      }
    };
  }, [
    chatId,
    latestMessageRole,
    messagesLength,
    setChatMeta,
    setMessages,
    status,
  ]);
}

export function PersistentAgentWorkspace({
  chatModel,
  draftChatId,
  initialSession,
  isChatAvailable,
  nodeVersion,
  persistenceLabel,
  recentChats,
  resumeLabel,
  setupMessage,
}: PersistentAgentWorkspaceProps) {
  const generatedChatIdRef = useRef(initialSession?.chat.id ?? draftChatId);
  const hasPromotedRouteRef = useRef(Boolean(initialSession));
  const chatId = generatedChatIdRef.current;
  const [chatMeta, setChatMeta] = useState(() => ({
    createdAt: initialSession?.chat.createdAt ?? null,
    id: chatId,
    updatedAt: initialSession?.chat.updatedAt ?? null,
  }));
  const { error, messages, resumeStream, sendMessage, setMessages, status } =
    useChat({
      id: chatId,
      messages: initialSession?.messages ?? [],
      resume: initialSession?.chat.activeStreamId != null,
      transport: new DefaultChatTransport({
        api: "/api/demos/persistent-agent",
        credentials: "include",
        prepareReconnectToStreamRequest: ({ id }) => ({
          api: `/api/demos/persistent-agent/${id}/stream`,
          credentials: "include",
        }),
        prepareSendMessagesRequest: ({ id, messages: nextMessages }) => ({
          body: {
            id,
            message: nextMessages.at(-1),
          },
        }),
      }),
    });
  const hasMessages = messages.length > 0;
  const isBusy = status === "submitted" || status === "streaming";
  const latestAssistant = [...messages]
    .reverse()
    .find((message) => message.role === "assistant");
  const latestMessageRole = messages.at(-1)?.role;
  const latestAssistantText = latestAssistant
    ? getTextContent(latestAssistant)
    : "";
  const showThinking = isBusy && latestAssistantText.length === 0;
  const showResumeThinking = shouldShowResumeThinking({
    initialSession,
    messages,
  });
  const submitStatus =
    showResumeThinking && status === "streaming" ? "submitted" : status;

  useEffect(() => {
    if (messages.length === 0) {
      return;
    }

    setChatMeta((current) => ({
      ...current,
      createdAt: current.createdAt ?? new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    }));
  }, [messages.length]);

  useResumeRecovery({
    chatId,
    initialSession,
    latestMessageRole,
    messagesLength: messages.length,
    setChatMeta,
    setMessages,
    status,
  });

  async function handleSubmit(text: string) {
    const trimmedText = text.trim();

    if (trimmedText.length === 0) {
      return;
    }

    if (!hasPromotedRouteRef.current) {
      hasPromotedRouteRef.current = true;
      window.history.replaceState({}, "", toConversationPath(chatId));
      setChatMeta((current) => ({
        ...current,
        createdAt: current.createdAt ?? new Date().toISOString(),
      }));
    }

    await sendMessage({ text: trimmedText });
  }

  function renderMessageBody(message: UIMessage) {
    const text = getTextContent(message);

    if (text) {
      return <MessageResponse>{text}</MessageResponse>;
    }

    if (message.role === "assistant" && showThinking) {
      return <Shimmer className="text-sm">Thinking...</Shimmer>;
    }

    return (
      <p className="text-muted-foreground text-sm">
        Waiting for visible output.
      </p>
    );
  }

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {error.message}
          </div>
        ) : null}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              <>
                {messages.map((message) => (
                  <Message from={message.role} key={message.id}>
                    <MessageContent
                      className={cn(
                        message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
                      )}
                    >
                      {renderMessageBody(message)}
                    </MessageContent>
                  </Message>
                ))}
                {showResumeThinking ? (
                  <Message from="assistant">
                    <MessageContent className="max-w-3xl">
                      <Shimmer className="text-sm">Thinking...</Shimmer>
                    </MessageContent>
                  </Message>
                ) : null}
              </>
            ) : (
              <ConversationEmptyState
                description="Start a conversation, refresh the page, and the same chat will restore under this URL."
                icon={<RobotIcon className="size-5" />}
                title="Persistent route is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => handleSubmit(text)}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Ask a question, refresh mid-stream, then return to the same URL."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">Visitor scoped</Badge>
                  <Badge variant="outline">{persistenceLabel}</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <PromptInputSubmit
                  disabled={!isChatAvailable}
                  status={submitStatus}
                />
              </PromptInputFooter>
            </PromptInput>
            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {persistentAgentSamplePrompts.map((prompt) => (
                  <Button
                    className="max-w-full justify-start text-left"
                    disabled={!isChatAvailable || isBusy}
                    key={prompt}
                    onClick={() => void handleSubmit(prompt)}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="border border-foreground/10 bg-background p-4 lg:min-h-0 lg:overflow-y-auto">
        <div className="space-y-5">
          <div className="flex items-center justify-between gap-2">
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Session
              </p>
              <p className="mt-1 font-medium text-sm">
                {initialSession ? "Restored route" : "New route promotion"}
              </p>
            </div>
            <Link
              className="inline-flex h-8 items-center justify-center border border-foreground/10 px-3 text-sm transition-colors hover:border-foreground/30"
              href="/demos/persistent-agent"
            >
              New chat
            </Link>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Chat ID
            </p>
            <p className="mt-1 break-all font-mono text-xs">{chatMeta.id}</p>
          </div>

          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-1">
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Created
              </p>
              <p className="mt-1 text-sm">
                {formatDateTime(chatMeta.createdAt)}
              </p>
            </div>
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Updated
              </p>
              <p className="mt-1 text-sm">
                {formatDateTime(chatMeta.updatedAt)}
              </p>
            </div>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Route contract
            </p>
            <p className="mt-1 text-sm">
              First send promotes this page into a stable URL. Refresh reloads
              messages from the active store. Redis-backed deployments can
              reconnect mid-stream through the resume endpoint.
            </p>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Recent chats
            </p>
            <div className="mt-2 grid gap-2">
              {recentChats.length > 0 ? (
                recentChats.slice(0, 6).map((chat) => (
                  <Link
                    className={cn(
                      "border px-3 py-2 text-left text-sm transition-colors",
                      chat.id === chatMeta.id
                        ? "border-foreground bg-foreground text-background"
                        : "border-foreground/10 hover:border-foreground/30"
                    )}
                    href={toConversationPath(chat.id)}
                    key={chat.id}
                  >
                    <div className="flex items-start justify-between gap-3">
                      <span className="line-clamp-2">{chat.title}</span>
                      <LinkIcon className="mt-0.5 size-3.5 shrink-0" />
                    </div>
                    <p
                      className={cn(
                        "mt-2 text-[11px]",
                        chat.id === chatMeta.id
                          ? "text-background/80"
                          : "text-muted-foreground"
                      )}
                    >
                      {formatDateTime(chat.updatedAt)}
                    </p>
                  </Link>
                ))
              ) : (
                <p className="text-muted-foreground text-sm">
                  No chats for this visitor yet.
                </p>
              )}
            </div>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Runtime
            </p>
            <div className="mt-2 flex flex-wrap gap-2">
              <Badge variant="outline">
                Node {nodeVersion.replace(nodeVersionPrefixPattern, "")}
              </Badge>
              <Badge variant="outline">HTTP-only cookie</Badge>
              <Badge variant="outline">{resumeLabel}</Badge>
            </div>
          </div>

          {initialSession?.chat.activeStreamId ? (
            <Button
              onClick={() => resumeStream()}
              size="sm"
              type="button"
              variant="outline"
            >
              <ArrowClockwiseIcon className="size-3.5" />
              Retry resume
            </Button>
          ) : null}
        </div>
      </aside>
    </div>
  );
}

import type { UIMessage } from "ai";

import type { PersistentAgentChatSession } from "@/lib/persistent-agent/server/chat-store";

export function shouldShowResumeThinking(input: {
  initialSession: PersistentAgentChatSession | null;
  messages: UIMessage[];
}) {
  const { initialSession, messages } = input;

  if (!initialSession?.chat.activeStreamId) {
    return false;
  }

  return messages.at(-1)?.role === "user";
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import { and, asc, desc, eq, lt } from "drizzle-orm";
import type { UIMessage } from "ai";
import {
  persistentAgentChats,
  persistentAgentMessages,
} from "./schema";
import { getPersistentAgentEnv } from "./env";
import { createPortablePersistentAgentChatPersistence } from "./portable-store";

const maxPersistentAgentTitleLength = 72;

export const persistentAgentCleanupCronScheduleUtc = "0 20 * * *";
export const persistentAgentCleanupRetentionDays = 7;

export interface PersistentAgentChatRecord {
  activeStreamId: string | null;
  createdAt: string;
  id: string;
  title: string;
  updatedAt: string;
  visitorId: string;
}

export interface PersistentAgentChatSession {
  chat: PersistentAgentChatRecord;
  messages: UIMessage[];
}

export interface PersistentAgentChatPersistence {
  listChatsForVisitor(visitorId: string): Promise<PersistentAgentChatRecord[]>;
  loadChatSession(
    chatId: string,
    visitorId: string
  ): Promise<PersistentAgentChatSession | null>;
  saveIncomingUserMessage(input: {
    chatId: string;
    message: UIMessage;
    visitorId: string;
  }): Promise<void>;
  saveFinishedMessages(input: {
    chatId: string;
    messages: UIMessage[];
    visitorId: string;
  }): Promise<void>;
  setActiveStream(input: {
    activeStreamId: string | null;
    chatId: string;
    visitorId: string;
  }): Promise<void>;
  cleanupExpiredChats(input?: { now?: Date }): Promise<{
    deletedChats: number;
    expiresBefore: string;
  }>;
}

interface PersistentAgentChatStoreDependencies {
  persistence?: PersistentAgentChatPersistence;
}

type PersistentAgentDatabaseModule = Awaited<
  ReturnType<typeof import("./database")["loadPersistentAgentDatabase"]>
>;

function toIsoString(value: Date | string) {
  return value instanceof Date ? value.toISOString() : value;
}

function normalizeChatRecord(record: {
  activeStreamId: string | null;
  createdAt: Date | string;
  id: string;
  title: string;
  updatedAt: Date | string;
  visitorId: string;
}): PersistentAgentChatRecord {
  return {
    activeStreamId: record.activeStreamId,
    createdAt: toIsoString(record.createdAt),
    id: record.id,
    title: record.title,
    updatedAt: toIsoString(record.updatedAt),
    visitorId: record.visitorId,
  };
}

async function loadPersistentAgentDatabase(): Promise<PersistentAgentDatabaseModule> {
  return import("./database").then((module) => module.loadPersistentAgentDatabase());
}

function getMessageText(message: UIMessage) {
  return message.parts
    .map((part) => (part.type === "text" ? part.text : ""))
    .filter((part) => part.length > 0)
    .join(" ")
    .replace(/\s+/g, " ")
    .trim();
}

function buildChatTitle(message: UIMessage) {
  const text = getMessageText(message);

  if (text.length === 0) {
    return "New chat";
  }

  return text.slice(0, maxPersistentAgentTitleLength);
}

function readMessageCreatedAt(message: UIMessage, fallback: Date) {
  const metadata = message.metadata as { createdAt?: string } | undefined;

  if (!metadata?.createdAt) {
    return fallback;
  }

  const createdAt = new Date(metadata.createdAt);

  return Number.isNaN(createdAt.valueOf()) ? fallback : createdAt;
}

function toUiMessage(row: {
  createdAt: Date | string;
  messageId: string;
  parts: unknown;
  role: string;
}) {
  return {
    id: row.messageId,
    metadata: {
      createdAt: toIsoString(row.createdAt),
    },
    parts: row.parts as UIMessage["parts"],
    role: row.role as UIMessage["role"],
  } satisfies UIMessage;
}

export function getPersistentAgentChatNotFoundError(chatId: string) {
  return `No persistent-agent chat found for ${chatId}.`;
}

function isInvalidPersistentAgentChatIdError(error: unknown) {
  const candidates =
    error instanceof Error
      ? [error, (error as Error & { cause?: unknown }).cause]
      : [error];

  return candidates.some((candidate) => {
    if (!(candidate instanceof Error)) {
      return false;
    }

    const candidateWithCode = candidate as Error & { code?: string };

    return (
      candidateWithCode.code === "22P02" ||
      candidate.message.includes("invalid input syntax for type uuid")
    );
  });
}

function createDatabaseBackedPersistentAgentChatPersistence(): PersistentAgentChatPersistence {
  return {
    async listChatsForVisitor(visitorId: string) {
      const { database, persistentAgentChats } =
        await loadPersistentAgentDatabase();
      const rows = await database
        .select()
        .from(persistentAgentChats)
        .where(eq(persistentAgentChats.visitorId, visitorId))
        .orderBy(desc(persistentAgentChats.updatedAt));

      return rows.map(normalizeChatRecord);
    },
    async loadChatSession(
      chatId: string,
      visitorId: string
    ): Promise<PersistentAgentChatSession | null> {
      try {
        const { database, persistentAgentChats, persistentAgentMessages } =
          await loadPersistentAgentDatabase();
        const [chat] = await database
          .select()
          .from(persistentAgentChats)
          .where(
            and(
              eq(persistentAgentChats.id, chatId),
              eq(persistentAgentChats.visitorId, visitorId)
            )
          )
          .limit(1);

        if (!chat) {
          return null;
        }

        const rows = await database
          .select()
          .from(persistentAgentMessages)
          .where(eq(persistentAgentMessages.chatId, chatId))
          .orderBy(asc(persistentAgentMessages.createdAt));

        return {
          chat: normalizeChatRecord(chat),
          messages: rows.map(toUiMessage),
        };
      } catch (error) {
        if (isInvalidPersistentAgentChatIdError(error)) {
          return null;
        }

        throw error;
      }
    },
    async saveIncomingUserMessage(input: {
      chatId: string;
      message: UIMessage;
      visitorId: string;
    }) {
      const { database, persistentAgentChats, persistentAgentMessages } =
        await loadPersistentAgentDatabase();
      const now = new Date();
      const title = buildChatTitle(input.message);

      await database.transaction(async (tx) => {
        const [existingChat] = await tx
          .select()
          .from(persistentAgentChats)
          .where(eq(persistentAgentChats.id, input.chatId))
          .limit(1);

        if (existingChat && existingChat.visitorId !== input.visitorId) {
          throw new Error(getPersistentAgentChatNotFoundError(input.chatId));
        }

        if (existingChat) {
          await tx
            .update(persistentAgentChats)
            .set({
              activeStreamId: null,
              title:
                existingChat.title === "New chat" && title !== "New chat"
                  ? title
                  : existingChat.title,
              updatedAt: now,
            })
            .where(eq(persistentAgentChats.id, input.chatId));
        } else {
          await tx.insert(persistentAgentChats).values({
            activeStreamId: null,
            id: input.chatId,
            title,
            updatedAt: now,
            visitorId: input.visitorId,
          });
        }

        await tx
          .insert(persistentAgentMessages)
          .values({
            attachments: [],
            chatId: input.chatId,
            createdAt: readMessageCreatedAt(input.message, now),
            messageId: input.message.id,
            parts: input.message.parts,
            role: input.message.role,
          })
          .onConflictDoUpdate({
            set: {
              parts: input.message.parts,
              role: input.message.role,
            },
            target: [
              persistentAgentMessages.chatId,
              persistentAgentMessages.messageId,
            ],
          });
      });
    },
    async saveFinishedMessages(input: {
      chatId: string;
      messages: UIMessage[];
      visitorId: string;
    }) {
      const { database, persistentAgentChats, persistentAgentMessages } =
        await loadPersistentAgentDatabase();
      const now = new Date();

      await database.transaction(async (tx) => {
        const [chat] = await tx
          .select()
          .from(persistentAgentChats)
          .where(
            and(
              eq(persistentAgentChats.id, input.chatId),
              eq(persistentAgentChats.visitorId, input.visitorId)
            )
          )
          .limit(1);

        if (!chat) {
          throw new Error(getPersistentAgentChatNotFoundError(input.chatId));
        }

        if (input.messages.length > 0) {
          await tx
            .insert(persistentAgentMessages)
            .values(
              input.messages.map((message) => ({
                attachments: [],
                chatId: input.chatId,
                createdAt: readMessageCreatedAt(message, now),
                messageId: message.id,
                parts: message.parts,
                role: message.role,
              }))
            )
            .onConflictDoNothing({
              target: [
                persistentAgentMessages.chatId,
                persistentAgentMessages.messageId,
              ],
            });
        }

        await tx
          .update(persistentAgentChats)
          .set({
            activeStreamId: null,
            updatedAt: now,
          })
          .where(eq(persistentAgentChats.id, input.chatId));
      });
    },
    async setActiveStream(input: {
      activeStreamId: string | null;
      chatId: string;
      visitorId: string;
    }) {
      const { database, persistentAgentChats } =
        await loadPersistentAgentDatabase();
      const rows = await database
        .update(persistentAgentChats)
        .set({
          activeStreamId: input.activeStreamId,
          updatedAt: new Date(),
        })
        .where(
          and(
            eq(persistentAgentChats.id, input.chatId),
            eq(persistentAgentChats.visitorId, input.visitorId)
          )
        )
        .returning({ id: persistentAgentChats.id });

      if (rows.length === 0) {
        throw new Error(getPersistentAgentChatNotFoundError(input.chatId));
      }
    },
    async cleanupExpiredChats(input?: { now?: Date }) {
      const { database, persistentAgentChats } =
        await loadPersistentAgentDatabase();
      const now = input?.now ?? new Date();
      const expiresBefore = new Date(
        now.getTime() -
          persistentAgentCleanupRetentionDays * 24 * 60 * 60 * 1000
      );
      const expiredChats = await database
        .select({ id: persistentAgentChats.id })
        .from(persistentAgentChats)
        .where(lt(persistentAgentChats.updatedAt, expiresBefore));

      if (expiredChats.length === 0) {
        return {
          deletedChats: 0,
          expiresBefore: expiresBefore.toISOString(),
        };
      }

      const deletedChats = await database
        .delete(persistentAgentChats)
        .where(lt(persistentAgentChats.updatedAt, expiresBefore))
        .returning({ id: persistentAgentChats.id });

      return {
        deletedChats: deletedChats.length,
        expiresBefore: expiresBefore.toISOString(),
      };
    },
  };
}

export function createPersistentAgentChatStore(
  dependencies: PersistentAgentChatStoreDependencies = {}
