interface PortablePersistentAgentState {
  chats: Map<string, PersistentAgentChatRecord>;
  messagesByChatId: Map<string, UIMessage[]>;
}

const globalStore = globalThis as typeof globalThis & {
  __persistentAgentPortableStore?: PortablePersistentAgentState;
};

function getPortableState(): PortablePersistentAgentState {
  globalStore.__persistentAgentPortableStore ??= {
    chats: new Map(),
    messagesByChatId: new Map(),
  };

  return globalStore.__persistentAgentPortableStore;
}

function nowIsoString() {
  return new Date().toISOString();
}

function cloneRecord<T>(value: T): T {
  return structuredClone(value);
}

function getMessageText(message: UIMessage) {
  return message.parts
    .map((part) => (part.type === "text" ? part.text : ""))
    .filter((part) => part.length > 0)
    .join(" ")
    .replace(/\s+/g, " ")
    .trim();
}

function buildChatTitle(message: UIMessage) {
  const text = getMessageText(message);

  if (text.length === 0) {
    return "New chat";
  }

  return text.slice(0, 72);
}

function normalizeMessageCreatedAt(message: UIMessage, fallback: string) {
  const metadata = message.metadata as { createdAt?: string } | undefined;

  if (!metadata?.createdAt) {
    return {
      ...message,
      metadata: {
        ...((message.metadata as Record<string, unknown> | undefined) ?? {}),
        createdAt: fallback,
      },
    };
  }

  const createdAt = new Date(metadata.createdAt);

  return {
    ...message,
    metadata: {
      ...((message.metadata as Record<string, unknown> | undefined) ?? {}),
      createdAt: Number.isNaN(createdAt.valueOf())
        ? fallback
        : createdAt.toISOString(),
    },
  };
}

function upsertMessage(messages: UIMessage[], nextMessage: UIMessage) {
  const existingIndex = messages.findIndex(
    (message) => message.id === nextMessage.id
  );

  if (existingIndex === -1) {
    return [...messages, nextMessage];
  }

  return messages.map((message, index) =>
    index === existingIndex ? nextMessage : message
  );
}

function assertChatForVisitor(
  chat: PersistentAgentChatRecord | undefined,
  chatId: string,
  visitorId: string
) {
  if (!chat || chat.visitorId !== visitorId) {
    throw new Error(getPersistentAgentChatNotFoundError(chatId));
  }

  return chat;
}

export function createPortablePersistentAgentChatPersistence(): PersistentAgentChatPersistence {
  const state = getPortableState();

  return {
    async listChatsForVisitor(visitorId) {
      return [...state.chats.values()]
        .filter((chat) => chat.visitorId === visitorId)
        .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
        .map(cloneRecord);
    },
    async loadChatSession(chatId, visitorId): Promise<PersistentAgentChatSession | null> {
      const chat = state.chats.get(chatId);

      if (!chat || chat.visitorId !== visitorId) {
        return null;
      }

      return {
        chat: cloneRecord(chat),
        messages: cloneRecord(state.messagesByChatId.get(chatId) ?? []),
      };
    },
    async saveIncomingUserMessage(input) {
      const timestamp = nowIsoString();
      const existingChat = state.chats.get(input.chatId);
      const title = buildChatTitle(input.message);

      if (existingChat && existingChat.visitorId !== input.visitorId) {
        throw new Error(getPersistentAgentChatNotFoundError(input.chatId));
      }

      const chat: PersistentAgentChatRecord = existingChat
        ? {
            ...existingChat,
            activeStreamId: null,
            title:
              existingChat.title === "New chat" && title !== "New chat"
                ? title
                : existingChat.title,
            updatedAt: timestamp,
          }
        : {
            activeStreamId: null,
            createdAt: timestamp,
            id: input.chatId,
            title,
            updatedAt: timestamp,
            visitorId: input.visitorId,
          };

      state.chats.set(input.chatId, chat);
      state.messagesByChatId.set(
        input.chatId,
        upsertMessage(
          state.messagesByChatId.get(input.chatId) ?? [],
          normalizeMessageCreatedAt(input.message, timestamp)
        )
      );
    },
    async saveFinishedMessages(input) {
      const timestamp = nowIsoString();
      const chat = assertChatForVisitor(
        state.chats.get(input.chatId),
        input.chatId,
        input.visitorId
      );
      const messages = input.messages.reduce(
        (currentMessages, message) =>
          upsertMessage(
            currentMessages,
            normalizeMessageCreatedAt(message, timestamp)
          ),
        state.messagesByChatId.get(input.chatId) ?? []
      );

      state.messagesByChatId.set(input.chatId, messages);
      state.chats.set(input.chatId, {
        ...chat,
        activeStreamId: null,
        updatedAt: timestamp,
      });
    },
    async setActiveStream(input) {
      const chat = assertChatForVisitor(
        state.chats.get(input.chatId),
        input.chatId,
        input.visitorId
      );

      state.chats.set(input.chatId, {
        ...chat,
        activeStreamId: input.activeStreamId,
        updatedAt: nowIsoString(),
      });
    },
    async cleanupExpiredChats(input) {
      const now = input?.now ?? new Date();
      const expiresBefore = new Date(
        now.getTime() -
          persistentAgentCleanupRetentionDays * 24 * 60 * 60 * 1000
      );
      let deletedChats = 0;

      for (const chat of state.chats.values()) {
        if (new Date(chat.updatedAt) >= expiresBefore) {
          continue;
        }

        state.chats.delete(chat.id);
        state.messagesByChatId.delete(chat.id);
        deletedChats += 1;
      }

      return {
        deletedChats,
        expiresBefore: expiresBefore.toISOString(),
      };
    },
  };
}

import {
  consumeStream,
  convertToModelMessages,
  createIdGenerator,
  generateId,
  streamText,
  UI_MESSAGE_STREAM_HEADERS,
  type UIMessage,
} from "ai";
import Redis from "ioredis";
import { after } from "next/dist/server/after";
import { createResumableStreamContext } from "resumable-stream/ioredis";

import {
  createPersistentAgentGateway,
  getPersistentAgentConfig,
  getPersistentAgentEnv,
  getPersistentAgentRedisConfig,
  getPersistentAgentSetupState,
  type PersistentAgentEnv,
} from "./env";
import {
  createPersistentAgentChatStore,
  getPersistentAgentChatNotFoundError,
  persistentAgentCleanupCronScheduleUtc,
  persistentAgentCleanupRetentionDays,
} from "./chat-store";

const invalidRequestBodyError =
  'Expected a JSON body with a non-empty "id" string and a "message" object.';

const persistentAgentSystemPrompt = [
  "You are the Persistent Agent demo in an AI SDK examples workspace.",
  "Answer like an experienced product engineer explaining architecture decisions.",
  "Keep replies concrete and concise.",
].join(" ");

interface PersistentAgentRequestBody {
  id?: string;
  message?: UIMessage;
}

export interface PersistentAgentRuntimeState {
  chatModel: string;
  cleanupRetentionDays: number;
  cleanupScheduleUtc: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  persistenceLabel: string;
  resumeLabel: string;
  resumeRequiresRedis: boolean;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

export function getPersistentAgentRuntimeState(
  env: PersistentAgentEnv = getPersistentAgentEnv()
): PersistentAgentRuntimeState {
  const setup = getPersistentAgentSetupState(env);

  return {
    chatModel: setup.config.chatModel,
    cleanupRetentionDays: persistentAgentCleanupRetentionDays,
    cleanupScheduleUtc: persistentAgentCleanupCronScheduleUtc,
    isChatAvailable: setup.isReady,
    nodeVersion: setup.nodeVersion,
    persistenceLabel: env.DATABASE_URL ? "Postgres" : "In-memory",
    resumeLabel: env.REDIS_URL ? "Redis resume" : "Local stream",
    resumeRequiresRedis: Boolean(env.REDIS_URL),
    setupMessage: setup.issues.length > 0 ? setup.issues.join(" ") : null,
    statusLabel: setup.isReady ? "Ready" : "Setup required",
  };
}

function readRequestBody(body: unknown) {
  const { id, message } = (body ?? {}) as PersistentAgentRequestBody;

  if (
    typeof id !== "string" ||
    id.trim().length === 0 ||
    !message ||
    typeof message !== "object"
  ) {
    throw new Error(invalidRequestBodyError);
  }

  return {
    id: id.trim(),
    message,
  };
}

let persistentAgentStreamContext:
  | ReturnType<typeof createResumableStreamContext>
  | undefined;
let persistentAgentStreamPublisher: Redis | undefined;
let persistentAgentStreamSubscriber: Redis | undefined;

function getStreamContext(env: PersistentAgentEnv) {
  const { redisUrl } = getPersistentAgentRedisConfig(env);

  if (!persistentAgentStreamPublisher) {
    persistentAgentStreamPublisher = new Redis(redisUrl, {
      enableReadyCheck: false,
    });
  }

  if (!persistentAgentStreamSubscriber) {
    persistentAgentStreamSubscriber = new Redis(redisUrl, {
      enableReadyCheck: false,
    });
  }

  persistentAgentStreamContext ??= createResumableStreamContext({
    publisher: persistentAgentStreamPublisher,
    subscriber: persistentAgentStreamSubscriber,
    waitUntil: after,
  });

  return persistentAgentStreamContext;
}

export async function handlePersistentAgentChatRequest(
  request: Request,
  viewer: { visitorId: string },
  env: PersistentAgentEnv = getPersistentAgentEnv()
) {
  const runtimeState = getPersistentAgentRuntimeState(env);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  let body: unknown;

  try {
    body = await request.json();
  } catch {
    return Response.json(
      {
        error: "Expected a valid JSON request body.",
      },
      { status: 400 }
    );
  }

  let input: { id: string; message: UIMessage };

  try {
    input = readRequestBody(body);
  } catch (error) {
    if (error instanceof Error && error.message === invalidRequestBodyError) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }

  const store = createPersistentAgentChatStore();
  const existingSession = await store.loadChatSession(
    input.id,
    viewer.visitorId
  );
  const originalMessages = existingSession
    ? [...existingSession.messages, input.message]
    : [input.message];

  try {
    await store.saveIncomingUserMessage({
      chatId: input.id,
      message: input.message,
      visitorId: viewer.visitorId,
    });
  } catch (error) {
    if (
      error instanceof Error &&
      error.message === getPersistentAgentChatNotFoundError(input.id)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 404 }
      );
    }

    throw error;
  }

  const gateway = createPersistentAgentGateway(env);
  const { chatModel } = getPersistentAgentConfig(env);
  const result = streamText({
    model: gateway(chatModel),
    messages: await convertToModelMessages(originalMessages),
    system: persistentAgentSystemPrompt,
  });
  const shouldUseRedisResume = Boolean(env.REDIS_URL);

  return result.toUIMessageStreamResponse({
    consumeSseStream: shouldUseRedisResume
      ? async ({ stream }) => {
          const streamId = generateId();
          await getStreamContext(env).createNewResumableStream(
            streamId,
            () => stream
          );
          await store.setActiveStream({
            activeStreamId: streamId,
            chatId: input.id,
            visitorId: viewer.visitorId,
          });
        }
      : consumeStream,
    generateMessageId: createIdGenerator({
      prefix: "pa-msg",
      size: 16,
    }),
    onFinish: async ({ isAborted, messages }) => {
      if (isAborted) {
        return;
      }

      await store.saveFinishedMessages({
        chatId: input.id,
        messages,
        visitorId: viewer.visitorId,
      });
    },
    originalMessages,
  });
}

export async function handlePersistentAgentStreamResumeRequest(
  chatId: string,
  viewer: { visitorId: string },
  env: PersistentAgentEnv = getPersistentAgentEnv()
) {
  const session = await createPersistentAgentChatStore().loadChatSession(
    chatId,
    viewer.visitorId
  );

  if (!session) {
    return Response.json(
      {
        error: getPersistentAgentChatNotFoundError(chatId),
      },
      { status: 404 }
    );
  }

  if (!session.chat.activeStreamId) {
    return new Response(null, { status: 204 });
  }

  if (!env.REDIS_URL) {
    return new Response(null, { status: 204 });
  }

  return new Response(
    await getStreamContext(env).resumeExistingStream(session.chat.activeStreamId),
    {
      headers: UI_MESSAGE_STREAM_HEADERS,
    }
  );
}

export async function handlePersistentAgentSessionRequest(
  chatId: string,
  viewer: { visitorId: string }
) {
  const session = await createPersistentAgentChatStore().loadChatSession(
    chatId,
    viewer.visitorId
  );

  if (!session) {
    return Response.json(
      {
        error: getPersistentAgentChatNotFoundError(chatId),
      },
      { status: 404 }
    );
  }

  return Response.json(session);
}

import {
  foreignKey,
  index,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from "drizzle-orm/pg-core";

export const persistentAgentChats = pgTable(
  "persistent_agent_chats",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    visitorId: varchar("visitor_id", { length: 191 }).notNull(),
    title: text("title").notNull(),
    activeStreamId: varchar("active_stream_id", { length: 191 }),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  (table) => ({
    visitorUpdatedIndex: index("persistent_agent_chats_visitor_updated_idx").on(
      table.visitorId,
      table.updatedAt
    ),
  })
);

export const persistentAgentMessages = pgTable(
  "persistent_agent_messages",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    chatId: uuid("chat_id").notNull(),
    messageId: varchar("message_id", { length: 191 }).notNull(),
    role: varchar("role", { length: 32 }).notNull(),
    parts: jsonb("parts").notNull(),
    attachments: jsonb("attachments").notNull(),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  (table) => ({
    chatCreatedIndex: index("persistent_agent_messages_chat_created_idx").on(
      table.chatId,
      table.createdAt
    ),
    chatMessageIdIndex: uniqueIndex(
      "persistent_agent_messages_chat_message_id_idx"
    ).on(table.chatId, table.messageId),
    chatForeignKey: foreignKey({
      columns: [table.chatId],
      foreignColumns: [persistentAgentChats.id],
      name: "persistent_agent_messages_chat_fk",
    }).onDelete("cascade"),
  })
);

export const persistentAgentSchema = {
  persistentAgentChats,
  persistentAgentMessages,
} as const;

import { cookies } from "next/headers";

import {
  createPersistentAgentChatStore,
  type PersistentAgentChatRecord,
  type PersistentAgentChatSession,
} from "./chat-store";
import { persistentAgentVisitorCookieName } from "./viewer-context";

export interface PersistentAgentScreenData {
  draftChatId: string;
  initialSession: PersistentAgentChatSession | null;
  recentChats: PersistentAgentChatRecord[];
  visitorId: string | null;
}

export async function loadPersistentAgentScreenData(input: {
  chatId?: string | null;
}) {
  const draftChatId = crypto.randomUUID();
  const cookieStore = await cookies();
  const visitorId =
    cookieStore.get(persistentAgentVisitorCookieName)?.value ?? null;

  if (!visitorId) {
    return {
      draftChatId,
      initialSession: null,
      recentChats: [],
      visitorId: null,
    } satisfies PersistentAgentScreenData;
  }

  const store = createPersistentAgentChatStore();
  const [initialSession, recentChats] = await Promise.all([
    input.chatId
      ? store.loadChatSession(input.chatId, visitorId)
      : Promise.resolve(null),
    store.listChatsForVisitor(visitorId),
  ]);

  return {
    draftChatId,
    initialSession,
    recentChats,
    visitorId,
  } satisfies PersistentAgentScreenData;
}

export const persistentAgentVisitorCookieName = "pa_visitor_id";

function parseCookieHeader(value: string | null) {
  if (!value) {
    return {};
  }

  return Object.fromEntries(
    value
      .split(";")
      .map((part) => part.trim())
      .filter((part) => part.length > 0)
      .map((part) => {
        const separatorIndex = part.indexOf("=");

        if (separatorIndex === -1) {
          return [part, ""] as const;
        }

        return [
          decodeURIComponent(part.slice(0, separatorIndex)),
          decodeURIComponent(part.slice(separatorIndex + 1)),
        ] as const;
      })
  );
}

export function readPersistentAgentVisitorIdFromCookieHeader(
  cookieHeader: string | null
) {
  const cookies = parseCookieHeader(cookieHeader);
  const visitorId = cookies[persistentAgentVisitorCookieName];

  return typeof visitorId === "string" && visitorId.trim().length > 0
    ? visitorId.trim()
    : null;
}

export function getOrCreatePersistentAgentVisitorId(request: Request) {
  const visitorId = readPersistentAgentVisitorIdFromCookieHeader(
    request.headers.get("cookie")
  );

  if (visitorId) {
    return {
      shouldSetCookie: false,
      visitorId,
    };
  }

  return {
    shouldSetCookie: true,
    visitorId: crypto.randomUUID(),
  };
}

export function buildPersistentAgentVisitorCookie(visitorId: string) {
  return `${persistentAgentVisitorCookieName}=${encodeURIComponent(visitorId)}; Path=/; HttpOnly; SameSite=Lax; Max-Age=${60 * 60 * 24 * 30}`;
}
